162: 	nextPanelId := getNextPanelId(panels)
163: 
164: 	for _, panel := range panels {
165: 		if panelID, ok := panel["id"].(float64); ok && panelID > 0 {
166: 			if ids[panelID] {
167: 				// Duplicate ID found, assign new one
168: 				panel["id"] = float64(nextPanelId)
169: 				nextPanelId++
170: 			} else {
171: 				// Valid unique ID, keep it
172: 				ids[panelID] = true
173: 			}
174: 		} else {
175: 			// No ID or invalid ID, assign new one
176: 			panel["id"] = float64(nextPanelId)
177: 			nextPanelId++
178: 		}
179: 	}
180: }
