39: type migrator struct {
40: 	ready      chan struct{}
41: 	migrations map[int]schemaversion.SchemaVersionMigrationFunc
42: }
43: 
44: func (m *migrator) init(dsInfoProvider schemaversion.DataSourceInfoProvider) {
45: 	initOnce.Do(func() {
46: 		m.migrations = schemaversion.GetMigrations(dsInfoProvider)
47: 		close(m.ready)
48: 	})
49: }
50: 
51: func (m *migrator) migrate(ctx context.Context, dash map[string]interface{}, targetVersion int) error {
52: 	if dash == nil {
53: 		return schemaversion.NewMigrationError("dashboard is nil", 0, targetVersion, "")
54: 	}
55: 
56: 	// wait for the migrator to be initialized
57: 	<-m.ready
58: 
59: 	// 0. Clean up dashboard properties that frontend never includes in save model
60: 	// These properties are added by backend but frontend filters them out
61: 	delete(dash, "__elements")
62: 	delete(dash, "__inputs")
63: 	delete(dash, "__requires")
64: 
65: 	// 1. Track which panels had transformations in original input (before any defaults applied)
66: 	// This is needed to match frontend hasOwnProperty behavior
67: 	trackOriginalTransformations(dash)
68: 
69: 	// 1.1. Track which panels had fieldConfig.defaults.custom in original input
70: 	// This is needed to preserve empty custom objects that were originally present
71: 	trackOriginalFieldConfigCustom(dash)
72: 
73: 	// 2. Apply ALL frontend defaults FIRST (DashboardModel + PanelModel defaults)
74: 	// This replicates the behavior of the frontend DashboardModel and PanelModel constructors
75: 	applyFrontendDefaults(dash)
76: 
77: 	// 2. Apply panel defaults to ALL panels (both top-level and nested in rows)
78: 	// The frontend creates PanelModel instances for all panels, including those in rows
79: 	if dashboardPanels, ok := dash["panels"].([]interface{}); ok {
80: 		for _, panelInterface := range dashboardPanels {
81: 			if panel, ok := panelInterface.(map[string]interface{}); ok {
82: 				applyPanelDefaults(panel)
83: 			}
84: 		}
85: 	}
86: 
87: 	// Apply defaults to panels inside rows (for pre-v16 dashboards)
88: 	// Match frontend upgradeToGridLayout: only panels NOT in collapsed rows get new PanelModel() constructor
89: 	if rows, ok := dash["rows"].([]interface{}); ok {
90: 		showRows := shouldShowRows(rows)
91: 
92: 		for _, rowInterface := range rows {
93: 			row, ok := rowInterface.(map[string]interface{})
94: 			if !ok {
95: 				continue
96: 			}
97: 
98: 			applyRowPanelDefaults(row, showRows)
99: 		}
100: 	}
101: 
102: 	// 3. Ensure panel IDs are unique for ALL panels (including nested ones)
103: 	// This matches the frontend ensurePanelsHaveUniqueIds() behavior
104: 	ensurePanelsHaveUniqueIds(dash)
105: 
106: 	// TODO: Probably we can check if we can migrate at the beginning of the function
107: 	// 4. Ensure schema version is set and if not default to 0
108: 	inputVersion := schemaversion.GetSchemaVersion(dash)
109: 	dash["schemaVersion"] = inputVersion
110: 
111: 	// If the schema version is older than the minimum version, with migration support,
112: 	// we don't migrate the dashboard.
113: 	if inputVersion < schemaversion.MIN_VERSION {
114: 		return schemaversion.NewMinimumVersionError(inputVersion)
115: 	}
116: 
117: 	// 5. Run existing migration pipeline UNCHANGED
118: 	// (All the existing v28, v29, etc. migrators run exactly as before)
119: 	for nextVersion := inputVersion + 1; nextVersion <= targetVersion; nextVersion++ {
120: 		if migration, ok := m.migrations[nextVersion]; ok {
121: 			if err := migration(ctx, dash); err != nil {
122: 				functionName := fmt.Sprintf("V%d", nextVersion)
123: 				return schemaversion.NewMigrationError("migration failed: "+err.Error(), inputVersion, nextVersion, functionName)
124: 			}
125: 			dash["schemaVersion"] = nextVersion
126: 		}
127: 	}
128: 
129: 	// 6. Add built-in annotation query after all migrations are complete
130: 	// This matches the frontend DashboardModel constructor behavior
131: 	addBuiltInAnnotationQuery(dash)
132: 
133: 	// 7. Clean up the dashboard to match frontend getSaveModel behavior
134: 	// This removes properties that shouldn't be persisted and filters out default values
135: 	cleanupDashboardForSave(dash)
136: 
137: 	if schemaversion.GetSchemaVersion(dash) != targetVersion {
138: 		return schemaversion.NewMigrationError("schema version not migrated to target version", inputVersion, targetVersion, "")
139: 	}
140: 
141: 	return nil
142: }
